import React, { useState, useEffect, useContext } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext } from '../../context/ThemeContext';
import Modal from '../Modal/Modal';

const Navbar = ({ isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const location = useLocation();
    const { theme, toggleTheme } = useContext(ThemeContext);
    const [hoveredMenu, setHoveredMenu] = useState(null);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [logoHovered, setLogoHovered] = useState(false);
    const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
    const [showLogoutModal, setShowLogoutModal] = useState(false);
    const [showSuccessModal, setShowSuccessModal] = useState(false);
    const [mobileDashboardOpen, setMobileDashboardOpen] = useState(false);

    const isDark = theme === 'dark';

    useEffect(() => {
        const handleScroll = () => {
            setScrolled(window.scrollY > 50);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    useEffect(() => {
        const handleResize = () => {
            setIsMobile(window.innerWidth < 768);
            if (window.innerWidth >= 768) {
                setMobileMenuOpen(false);
            }
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const navigateTo = (path) => {
        navigate(path);
        setMobileMenuOpen(false);
    };

    const handleLogoutClick = () => {
        setShowLogoutModal(true);
    };

    const confirmLogout = () => {
        handleLogout();
        setShowLogoutModal(false);
        setShowSuccessModal(true);
        setTimeout(() => {
            setShowSuccessModal(false);
        }, 2000);
    };

    const getMenuStyle = (menuPath) => ({
        background: 'none', 
        border: 'none',
        color: hoveredMenu === menuPath || location.pathname === menuPath ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
        fontWeight: '700', 
        cursor: 'pointer', 
        fontSize: isMobile ? '18px' : '14px', 
        transition: 'all 0.3s ease',
        padding: '12px 0',
        position: 'relative',
        letterSpacing: '0.3px',
        width: isMobile ? '100%' : 'auto',
        textAlign: isMobile ? 'center' : 'left'
    });

    const renderDropdownItem = (path, label, icon) => (
        <button 
            onClick={() => { navigateTo(path); setHoveredMenu(null); }}
            style={{
                background: location.pathname === path ? (isDark ? '#292524' : '#fef5e7') : 'transparent',
                border: 'none',
                color: location.pathname === path ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                fontWeight: location.pathname === path ? '700' : '600',
                cursor: 'pointer',
                fontSize: '13px',
                padding: '10px 16px',
                borderRadius: '8px',
                transition: 'all 0.2s ease',
                textAlign: 'left',
                width: '100%',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                whiteSpace: 'nowrap'
            }}
            onMouseEnter={(e) => { e.currentTarget.style.background = isDark ? '#292524' : '#fef5e7'; }}
            onMouseLeave={(e) => { 
                e.currentTarget.style.background = location.pathname === path ? (isDark ? '#292524' : '#fef5e7') : 'transparent';
            }}
        >
            {icon} {label}
        </button>
    );

    const getMobileNavItems = () => {
        const baseItems = [
            { path: '/', icon: '🏠', label: 'Beranda' },
            { path: '/eksplorasi', icon: '🔍', label: 'Cari' },
        ];
        if (!isAuthenticated) {
            baseItems.push({ path: '/login', icon: '🔑', label: 'Login' });
        } else if (userRole === 'Pelamar') {
            baseItems.push(
                { path: '/favorit', icon: '⭐', label: 'Favorit' },
                { path: '/status-lamaran', icon: '📋', label: 'Status' },
                { path: '/profile', icon: '👤', label: 'Profil' },
            );
        } else if (userRole === 'Perusahaan') {
            baseItems.push(
                { path: '/hrd/dashboard', icon: '📊', label: 'Dashboard' },
                { path: '/hrd/branding', icon: '🏢', label: 'Branding' },
            );
        } else if (userRole === 'Admin') {
            baseItems.push(
                { path: '/admin/dashboard', icon: '⚙️', label: 'Admin' },
            );
        }
        return baseItems;
    };

    return (
        <>
            {/* Logout Confirmation Modal */}
            <Modal
                isOpen={showLogoutModal}
                onClose={() => setShowLogoutModal(false)}
                title="Konfirmasi Logout"
                message="Apakah Anda yakin ingin keluar dari akun Anda?"
                type="warning"
                onConfirm={confirmLogout}
            />

            {/* Success Logout Modal */}
            <Modal
                isOpen={showSuccessModal}
                onClose={() => setShowSuccessModal(false)}
                title="Berhasil Logout"
                message="Anda telah berhasil keluar dari akun. Sampai jumpa kembali!"
                type="success"
            />

            <nav style={{ 
                display: 'flex', 
                justifyContent: 'space-between', 
                alignItems: 'center', 
                padding: scrolled ? '12px 4%' : '16px 4%', 
                background: scrolled 
                    ? (isDark ? 'rgba(12, 10, 9, 0.95)' : 'rgba(245, 245, 244, 0.95)')
                    : (isDark ? '#0c0a09' : '#f5f5f4'), 
                borderBottom: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`,
                position: 'sticky',
                top: 0,
                zIndex: 1000,
                transition: 'all 0.3s ease',
                backdropFilter: scrolled ? 'blur(10px)' : 'none'
            }}>
                {/* Logo Section */}
                <div 
                    onClick={() => navigateTo('/')} 
                    style={{ 
                        cursor: 'pointer',
                        transition: 'all 0.3s ease',
                        display: 'flex',
                        alignItems: 'center',
                        gap: isMobile ? '6px' : '8px'
                    }}
                    onMouseEnter={(e) => {
                        if (!isMobile) {
                            setLogoHovered(true);
                            e.currentTarget.style.transform = 'scale(1.02)';
                        }
                    }}
                    onMouseLeave={(e) => {
                        if (!isMobile) {
                            setLogoHovered(false);
                            e.currentTarget.style.transform = 'scale(1)';
                        }
                    }}
                >
                    <div style={{
                        width: isMobile ? '32px' : '36px',
                        height: isMobile ? '32px' : '36px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        background: `linear-gradient(135deg, #ea580c, #f59e0b)`,
                        borderRadius: '10px',
                        transform: !isMobile && logoHovered ? 'rotate(5deg) scale(1.05)' : 'rotate(0deg) scale(1)',
                        transition: 'all 0.3s ease',
                        boxShadow: !isMobile && logoHovered ? '0 4px 15px rgba(234, 88, 12, 0.4)' : 'none'
                    }}>
                        <span style={{
                            fontSize: isMobile ? '16px' : '18px',
                            fontWeight: '900',
                            color: '#fff'
                        }}>
                            ⚡
                        </span>
                    </div>

                    <div>
                        <h2 style={{ 
                            color: isDark ? '#fef3c7' : '#1c1917', 
                            margin: 0, 
                            fontSize: isMobile ? '18px' : '22px',
                            fontWeight: '800',
                            letterSpacing: '-0.5px',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '2px',
                            flexWrap: 'wrap'
                        }}>
                            <span style={{ 
                                background: 'linear-gradient(135deg, #ea580c, #f59e0b)',
                                backgroundClip: 'text',
                                WebkitBackgroundClip: 'text',
                                color: 'transparent'
                            }}>
                                Pasukan
                            </span>
                            <span style={{ color: '#ea580c' }}>Yerus</span>
                            <span style={{ color: isDark ? '#fef3c7' : '#1c1917' }}>Solo</span>
                        </h2>
                        {!isMobile && (
                            <div style={{
                                fontSize: '8px',
                                letterSpacing: '1px',
                                color: '#ea580c',
                                textTransform: 'uppercase',
                                fontWeight: '700',
                                marginTop: '2px',
                                opacity: logoHovered ? 1 : 0.7,
                                transition: 'opacity 0.3s ease'
                            }}>
                                #1 Portal Karir
                            </div>
                        )}
                    </div>
                </div>

                {/* Desktop Menu */}
                <div className="nav-menu" style={{ 
                    display: isMobile ? 'none' : 'flex', 
                    gap: '30px', 
                    alignItems: 'center',
                    flexWrap: 'wrap'
                }}>
                    <button 
                        style={getMenuStyle('/')} 
                        onClick={() => navigateTo('/')} 
                        onMouseEnter={() => setHoveredMenu('/')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Beranda
                        {location.pathname === '/' && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>
                    <button 
                        style={getMenuStyle('/eksplorasi')} 
                        onClick={() => navigateTo('/eksplorasi')} 
                        onMouseEnter={() => setHoveredMenu('/eksplorasi')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Lowongan
                        {location.pathname === '/eksplorasi' && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>

                    {/* Dashboard Dropdown - Pelamar & Perusahaan */}
                    {isAuthenticated && (userRole === 'Pelamar' || userRole === 'Perusahaan') && (
                        <div 
                            style={{ position: 'relative' }}
                            onMouseEnter={() => setHoveredMenu('dashboard')}
                            onMouseLeave={() => setHoveredMenu(null)}
                        >
                            <button 
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: hoveredMenu === 'dashboard' || 
                                        ['/profile', '/favorit', '/status-lamaran', '/hrd/dashboard'].includes(location.pathname) 
                                        ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                    fontWeight: '700',
                                    cursor: 'pointer',
                                    fontSize: '14px',
                                    transition: 'all 0.3s ease',
                                    padding: '8px 0',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '4px',
                                    position: 'relative'
                                }}
                                onMouseEnter={() => setHoveredMenu('dashboard')}
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Dashboard
                                <span style={{ fontSize: '10px', marginTop: '1px' }}>▾</span>
                                {['/profile', '/favorit', '/status-lamaran', '/hrd/dashboard'].includes(location.pathname) && (
                                    <span style={{
                                        position: 'absolute',
                                        bottom: '0',
                                        left: '0',
                                        width: '100%',
                                        height: '2px',
                                        background: '#ea580c',
                                        borderRadius: '2px'
                                    }} />
                                )}
                            </button>
                            {hoveredMenu === 'dashboard' && (
                                <div 
                                    style={{
                                        position: 'absolute',
                                        top: '100%',
                                        left: '50%',
                                        transform: 'translateX(-50%)',
                                        background: isDark ? '#1c1917' : '#ffffff',
                                        border: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`,
                                        borderRadius: '12px',
                                        padding: '6px',
                                        boxShadow: '0 10px 30px rgba(0,0,0,0.15)',
                                        minWidth: '200px',
                                        zIndex: 100,
                                        display: 'flex',
                                        flexDirection: 'column',
                                        gap: '2px'
                                    }}
                                    onMouseEnter={() => setHoveredMenu('dashboard')}
                                    onMouseLeave={() => setHoveredMenu(null)}
                                >
                                    {userRole === 'Pelamar' ? (
                                        <>
                                            {renderDropdownItem('/profile', 'Info Profil', '👤')}
                                            {renderDropdownItem('/favorit', 'Lamar yang Disimpan', '⭐')}
                                            {renderDropdownItem('/status-lamaran', 'Apply Tracker', '📋')}
                                        </>
                                    ) : (
                                        <>
                                            {renderDropdownItem('/hrd/dashboard', 'Pembuat Lowongan', '📝')}
                                            {renderDropdownItem('/hrd/dashboard', 'Lamaran Masuk', '📥')}
                                        </>
                                    )}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Branding - Perusahaan */}
                    {isAuthenticated && userRole === 'Perusahaan' && (
                        <button 
                            onClick={() => navigateTo('/hrd/branding')}
                            style={{
                                background: 'none',
                                border: 'none',
                                color: hoveredMenu === '/hrd/branding' ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                fontWeight: '700',
                                cursor: 'pointer',
                                fontSize: '14px',
                                transition: 'all 0.3s ease',
                                padding: '8px 0'
                            }}
                            onMouseEnter={() => setHoveredMenu('/hrd/branding')}
                            onMouseLeave={() => setHoveredMenu(null)}
                        >
                             Branding
                        </button>
                    )}

                    {/* Role-based menu - Admin */}
                    {isAuthenticated && userRole === 'Admin' && (
                        <button 
                            onClick={() => navigateTo('/admin/dashboard')}
                            style={{
                                background: 'none',
                                border: 'none',
                                color: hoveredMenu === '/admin/dashboard' ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                fontWeight: '700',
                                cursor: 'pointer',
                                fontSize: '14px',
                                transition: 'all 0.3s ease',
                                padding: '8px 0'
                            }}
                            onMouseEnter={() => setHoveredMenu('/admin/dashboard')}
                            onMouseLeave={() => setHoveredMenu(null)}
                        >
                             Admin Panel
                        </button>
                    )}
                </div>

                {/* Right Section */}
                <div style={{ display: 'flex', alignItems: 'center', gap: isMobile ? '8px' : '15px' }}>
                    <button
                        onClick={toggleTheme}
                        style={{
                            background: isDark ? '#1c1917' : '#e5e5e5',
                            border: `1px solid ${isDark ? '#262626' : '#d4d4d4'}`,
                            borderRadius: '50%',
                            width: isMobile ? '36px' : '40px',
                            height: isMobile ? '36px' : '40px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            transition: 'all 0.3s ease',
                            fontSize: isMobile ? '16px' : '18px'
                        }}
                        onMouseEnter={(e) => {
                            e.currentTarget.style.transform = 'scale(1.1)';
                            e.currentTarget.style.boxShadow = '0 2px 10px rgba(0,0,0,0.2)';
                        }}
                        onMouseLeave={(e) => {
                            e.currentTarget.style.transform = 'scale(1)';
                            e.currentTarget.style.boxShadow = 'none';
                        }}
                    >
                        {isDark ? '☀️' : '🌙'}
                    </button>

                    {!isMobile && (
                        <>
                            {isAuthenticated ? (
                                <button 
                                    onClick={handleLogoutClick}
                                    style={{ 
                                        padding: '8px 20px', 
                                        borderRadius: '30px', 
                                        border: '1px solid #ef4444', 
                                        color: '#ef4444', 
                                        cursor: 'pointer', 
                                        background: 'transparent',
                                        fontWeight: '600',
                                        fontSize: '13px',
                                        transition: 'all 0.3s ease'
                                    }}
                                    onMouseEnter={(e) => {
                                        e.currentTarget.style.background = '#ef4444';
                                        e.currentTarget.style.color = '#fff';
                                        e.currentTarget.style.transform = 'translateY(-2px)';
                                    }}
                                    onMouseLeave={(e) => {
                                        e.currentTarget.style.background = 'transparent';
                                        e.currentTarget.style.color = '#ef4444';
                                        e.currentTarget.style.transform = 'translateY(0)';
                                    }}
                                >
                                    Keluar
                                </button>
                            ) : (
                                <button 
                                    onClick={() => navigateTo('/login')} 
                                    style={{ 
                                        padding: '8px 24px', 
                                        borderRadius: '30px', 
                                        border: '1px solid #ea580c', 
                                        background: hoveredMenu === '/login' ? '#ea580c' : 'transparent', 
                                        color: hoveredMenu === '/login' ? '#fff' : '#ea580c', 
                                        fontWeight: '700', 
                                        fontSize: '13px', 
                                        cursor: 'pointer', 
                                        transition: 'all 0.3s ease',
                                        boxShadow: hoveredMenu === '/login' ? '0 4px 15px rgba(234,88,12,0.3)' : 'none'
                                    }}
                                    onMouseEnter={(e) => {
                                        setHoveredMenu('/login');
                                        e.currentTarget.style.transform = 'translateY(-2px)';
                                    }}
                                    onMouseLeave={(e) => {
                                        setHoveredMenu(null);
                                        e.currentTarget.style.transform = 'translateY(0)';
                                    }}
                                >
                                    Login
                                </button>
                            )}
                        </>
                    )}

                    <button 
                        onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                        style={{
                            display: isMobile ? 'block' : 'none',
                            background: 'none',
                            border: 'none',
                            color: isDark ? '#fff' : '#1c1917',
                            fontSize: '24px',
                            cursor: 'pointer',
                            padding: '8px',
                            width: '40px',
                            height: '40px',
                            borderRadius: '8px',
                            transition: 'all 0.3s ease'
                        }}
                        onMouseEnter={(e) => {
                            e.currentTarget.style.background = isDark ? '#1c1917' : '#e5e5e5';
                        }}
                        onMouseLeave={(e) => {
                            e.currentTarget.style.background = 'transparent';
                        }}
                    >
                        {mobileMenuOpen ? '✕' : '☰'}
                    </button>
                </div>
            </nav>

            {/* Mobile Menu */}
            {mobileMenuOpen && (
                <div style={{
                    position: 'fixed',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    background: isDark ? '#0c0a09' : '#f5f5f4',
                    zIndex: 999,
                    padding: '70px 20px 30px 20px',
                    animation: 'slideIn 0.3s ease',
                    overflowY: 'auto'
                }}>
                    <button 
                        onClick={() => setMobileMenuOpen(false)}
                        style={{
                            position: 'absolute',
                            top: '16px',
                            right: '16px',
                            background: isDark ? '#1c1917' : '#e5e5e5',
                            border: 'none',
                            color: isDark ? '#fff' : '#1c1917',
                            fontSize: '20px',
                            cursor: 'pointer',
                            width: '40px',
                            height: '40px',
                            borderRadius: '10px',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center'
                        }}
                    >
                        ✕
                    </button>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                        <div style={{
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '12px',
                            marginBottom: '20px',
                            paddingBottom: '20px',
                            borderBottom: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`
                        }}>
                            <div style={{
                                width: '45px',
                                height: '45px',
                                background: `linear-gradient(135deg, #ea580c, #f59e0b)`,
                                borderRadius: '12px',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}>
                                <span style={{ fontSize: '22px', color: '#fff' }}>⚡</span>
                            </div>
                            <div>
                                <h2 style={{ 
                                    color: isDark ? '#fef3c7' : '#1c1917', 
                                    margin: 0, 
                                    fontSize: '20px',
                                    fontWeight: '800'
                                }}>
                                    Pasukan<span style={{ color: '#ea580c' }}>Yerus</span>Solo
                                </h2>
                                <div style={{
                                    fontSize: '10px',
                                    color: '#ea580c',
                                    textAlign: 'center',
                                    marginTop: '4px'
                                }}>
                                    #1 Portal Karir
                                </div>
                            </div>
                        </div>

                        <button 
                            onClick={() => navigateTo('/')} 
                            style={{
                                ...getMenuStyle('/'),
                                padding: '14px 20px',
                                borderRadius: '12px'
                            }}
                        >
                             Beranda
                        </button>
                        <button 
                            onClick={() => navigateTo('/eksplorasi')} 
                            style={{
                                ...getMenuStyle('/eksplorasi'),
                                padding: '14px 20px',
                                borderRadius: '12px'
                            }}
                        >
                             Lowongan
                        </button>

                        {/* Dashboard - Mobile */}
                        {isAuthenticated && (userRole === 'Pelamar' || userRole === 'Perusahaan') && (
                            <>
                                <div 
                                    onClick={() => setMobileDashboardOpen(!mobileDashboardOpen)}
                                    style={{
                                        padding: '14px 20px',
                                        borderRadius: '12px',
                                        color: isDark ? '#fff' : '#1c1917',
                                        background: 'none',
                                        border: 'none',
                                        fontSize: '18px',
                                        fontWeight: '800',
                                        cursor: 'pointer',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'space-between',
                                        width: '100%',
                                        textAlign: 'left'
                                    }}
                                >
                                    <span>📊 Dashboard</span>
                                    <span style={{ fontSize: '14px', transition: 'transform 0.3s ease', transform: mobileDashboardOpen ? 'rotate(180deg)' : 'rotate(0deg)' }}>▾</span>
                                </div>
                                {mobileDashboardOpen && (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', paddingLeft: '24px' }}>
                                        {userRole === 'Pelamar' ? (
                                            <>
                                                <button onClick={() => { navigateTo('/profile'); setMobileDashboardOpen(false); }} style={{ padding: '12px 16px', borderRadius: '10px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '16px', fontWeight: '600', textAlign: 'left', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    👤 Info Profil
                                                </button>
                                                <button onClick={() => { navigateTo('/favorit'); setMobileDashboardOpen(false); }} style={{ padding: '12px 16px', borderRadius: '10px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '16px', fontWeight: '600', textAlign: 'left', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    ⭐ Lamar yang Disimpan
                                                </button>
                                                <button onClick={() => { navigateTo('/status-lamaran'); setMobileDashboardOpen(false); }} style={{ padding: '12px 16px', borderRadius: '10px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '16px', fontWeight: '600', textAlign: 'left', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    📋 Apply Tracker
                                                </button>
                                            </>
                                        ) : (
                                            <>
                                                <button onClick={() => { navigateTo('/hrd/dashboard'); setMobileDashboardOpen(false); }} style={{ padding: '12px 16px', borderRadius: '10px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '16px', fontWeight: '600', textAlign: 'left', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    📝 Pembuat Lowongan
                                                </button>
                                                <button onClick={() => { navigateTo('/hrd/dashboard'); setMobileDashboardOpen(false); }} style={{ padding: '12px 16px', borderRadius: '10px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '16px', fontWeight: '600', textAlign: 'left', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    📥 Lamaran Masuk
                                                </button>
                                            </>
                                        )}
                                    </div>
                                )}

                                {/* Branding - Perusahaan (Mobile) */}
                                {userRole === 'Perusahaan' && (
                                    <button onClick={() => navigateTo('/hrd/branding')} style={{ padding: '14px 20px', borderRadius: '12px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '18px', fontWeight: '700', textAlign: 'left', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}>
                                        🏢 Branding
                                    </button>
                                )}
                            </>
                        )}

                        {/* Role-based menu - Admin (Mobile) */}
                        {isAuthenticated && userRole === 'Admin' && (
                            <button onClick={() => navigateTo('/admin/dashboard')} style={{ padding: '14px 20px', borderRadius: '12px', color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '18px', fontWeight: '700' }}>
                                ⚙️ Admin Panel
                            </button>
                        )}

                        <div style={{
                            marginTop: '20px',
                            paddingTop: '20px',
                            borderTop: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`
                        }}>
                            {isAuthenticated ? (
                                <button 
                                    onClick={handleLogoutClick}
                                    style={{ 
                                        width: '100%',
                                        padding: '14px 20px', 
                                        borderRadius: '30px', 
                                        border: '1px solid #ef4444', 
                                        color: '#ef4444', 
                                        cursor: 'pointer', 
                                        background: 'transparent',
                                        fontWeight: '600',
                                        fontSize: '16px'
                                    }}
                                >
                                    🚪 Keluar
                                </button>
                            ) : (
                                <button 
                                    onClick={() => navigateTo('/login')} 
                                    style={{ 
                                        width: '100%',
                                        padding: '14px 20px', 
                                        borderRadius: '30px', 
                                        background: 'linear-gradient(135deg, #ea580c, #f59e0b)',
                                        color: '#fff', 
                                        fontWeight: '700', 
                                        fontSize: '16px', 
                                        cursor: 'pointer', 
                                        border: 'none'
                                    }}
                                >
                                    🔑 Login / Daftar
                                </button>
                            )}
                        </div>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes slideIn {
                    from { transform: translateX(100%); }
                    to { transform: translateX(0); }
                }
                @media (max-width: 768px) {
                    .nav-menu { display: none !important; }
                }
                @media (max-width: 480px) {
                    nav { padding: 12px 3% !important; }
                }
            `}</style>
        </>
    );
};

export default Navbar;
